"use strict";(self.webpackChunksample=self.webpackChunksample||[]).push([[6739],{35943:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>s,contentTitle:()=>a,default:()=>d,frontMatter:()=>o,metadata:()=>l,toc:()=>c});var r=n(74848),i=n(28453);const o={slug:"\ub098\uc774\uc640 \ucc44\uc6a9\uc5d0 \ub300\ud55c \uc9e7\uc740 \uc0dd\uac01.",title:"\ub098\uc774\uc640 \ucc44\uc6a9\uc5d0 \ub300\ud55c \uc9e7\uc740 \uc0dd\uac01.",authors:"ryukato",date:new Date("2018-01-24T16:57:29.000Z"),tags:["recruit","getting-old"]},a="\ub098\uc774\uc640 \ub9c8\uc778\ub4dc \uc14b",l={permalink:"/blog/\ub098\uc774\uc640 \ucc44\uc6a9\uc5d0 \ub300\ud55c \uc9e7\uc740 \uc0dd\uac01.",source:"@site/blog/2018-01-24-thinking-about-age-and-job.md",title:"\ub098\uc774\uc640 \ucc44\uc6a9\uc5d0 \ub300\ud55c \uc9e7\uc740 \uc0dd\uac01.",description:"\uba87\uc77c\uc804 \uba87\uba87 \ud68c\uc0ac\uc640 \ud5e4\ub4dc\ud5cc\ud130\ub4e4\uc774 \uc80b\uc740 \uc5f0\ub839\ub300\uc758 \ubd84\ub4e4\ub9cc\uc744 \ub300\uc0c1\uc73c\ub85c \uad6c\uc778\uc744 \ud558\uace0 \uc788\ub2e4\ub294 \uae00\uc744 \uc77d\uc740 \uc801\uc774 \uc788\ub2e4. \uadf8\ub9ac\uace0 \uadf8 \uae00\uc5d0\ub300\ud55c \ub2f5\uae00 \uc911\uc5d0\ub294 \ub098\uc774\uac00 \ub9ce\uc740\uba74 \ub9c8\uc778\ub4dc \uc14b\uc774 \ub2eb\ud600\uc11c \ud604\uc7ac\uc758 \ube60\ub974\uac8c \ubcc0\ud654\ud558\ub294 \ud658\uacbd\uacfc \uc774\uc804\uc758 Legacy\uc640 \uac19\uc740 \uc5c5\ubb34 \uc218\ud589 \ubc29\ubc95\uacfc\ub294 \ub2e4\ub978 \uc0c8\ub85c\uc6b4 \uc5c5\ubb34 \ubc29\ubc95\uc5d0 \uc801\uc751\uc744 \ud560 \uc218 \uc5c6\ub2e4\ub77c\ub294 \ub2f5\uae00\uc774 \uc788\uc5c8\ub2e4. \uadf8\ub7f0\ub370 \uc774\uac8c \uc815\ub9d0 \ub098\uc774\uc640 \uc0c1\uad00\uc774 \uc788\uc744\uae4c? \ub098\uc774\uac00 \ub9ce\uc73c\uba74 \uc0c8\ub85c\uc6b4 \ubcc0\ud654\uc640 \ud658\uacbd\uc5d0 \uc801\uc751\ud558\uae30 \ud798\ub4e0\uac78\uae4c? \ubc18\ub300\ub85c \ub098\uc774\uac00 \uc801\uc73c\uba74 \uc27d\uac8c \uc801\uc751 \ud560 \uc218 \uc788\ub2e4\ub294 \uac83\uc77c\uae4c?",date:"2018-01-24T16:57:29.000Z",tags:[{label:"recruit",permalink:"/blog/tags/recruit"},{label:"getting-old",permalink:"/blog/tags/getting-old"}],readingTime:10.305,hasTruncateMarker:!0,authors:[{name:"Ryukato",title:"BackEnd Software Developer",url:"https://github.com/ryukato",imageURL:"https://github.com/ryukato.png",key:"ryukato"}],frontMatter:{slug:"\ub098\uc774\uc640 \ucc44\uc6a9\uc5d0 \ub300\ud55c \uc9e7\uc740 \uc0dd\uac01.",title:"\ub098\uc774\uc640 \ucc44\uc6a9\uc5d0 \ub300\ud55c \uc9e7\uc740 \uc0dd\uac01.",authors:"ryukato",date:"2018-01-24T16:57:29.000Z",tags:["recruit","getting-old"]},unlisted:!1,prevItem:{title:"Money in the XRP Ledger",permalink:"/blog/Money in the XRP Ledger"},nextItem:{title:"Secure Coding Summary and Practices",permalink:"/blog/Secure Coding Summary and Practices"}},s={authorsImageUrls:[void 0]},c=[{value:"&quot;\ub098\uc774&quot;\ub77c\ub294 \ucee8\ud14d\uc2a4\ud2b8\uc758 \uc758\ubbf8",id:"\ub098\uc774\ub77c\ub294-\ucee8\ud14d\uc2a4\ud2b8\uc758-\uc758\ubbf8",level:2},{value:"&quot;\ub098\uc774&quot;\uc640 \ub2a5\ub825 \uadf8\ub9ac\uace0 \uc18c\ud1b5",id:"\ub098\uc774\uc640-\ub2a5\ub825-\uadf8\ub9ac\uace0-\uc18c\ud1b5",level:2},{value:"\uadf8\ub7fc \ubb34\uc5c7\uc744 \ubd10\uc57c \ud558\ub098?",id:"\uadf8\ub7fc-\ubb34\uc5c7\uc744-\ubd10\uc57c-\ud558\ub098",level:2}];function u(e){const t={h2:"h2",p:"p",...(0,i.R)(),...e.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(t.p,{children:"\uba87\uc77c\uc804 \uba87\uba87 \ud68c\uc0ac\uc640 \ud5e4\ub4dc\ud5cc\ud130\ub4e4\uc774 \uc80b\uc740 \uc5f0\ub839\ub300\uc758 \ubd84\ub4e4\ub9cc\uc744 \ub300\uc0c1\uc73c\ub85c \uad6c\uc778\uc744 \ud558\uace0 \uc788\ub2e4\ub294 \uae00\uc744 \uc77d\uc740 \uc801\uc774 \uc788\ub2e4. \uadf8\ub9ac\uace0 \uadf8 \uae00\uc5d0\ub300\ud55c \ub2f5\uae00 \uc911\uc5d0\ub294 \ub098\uc774\uac00 \ub9ce\uc740\uba74 \ub9c8\uc778\ub4dc \uc14b\uc774 \ub2eb\ud600\uc11c \ud604\uc7ac\uc758 \ube60\ub974\uac8c \ubcc0\ud654\ud558\ub294 \ud658\uacbd\uacfc \uc774\uc804\uc758 Legacy\uc640 \uac19\uc740 \uc5c5\ubb34 \uc218\ud589 \ubc29\ubc95\uacfc\ub294 \ub2e4\ub978 \uc0c8\ub85c\uc6b4 \uc5c5\ubb34 \ubc29\ubc95\uc5d0 \uc801\uc751\uc744 \ud560 \uc218 \uc5c6\ub2e4\ub77c\ub294 \ub2f5\uae00\uc774 \uc788\uc5c8\ub2e4. \uadf8\ub7f0\ub370 \uc774\uac8c \uc815\ub9d0 \ub098\uc774\uc640 \uc0c1\uad00\uc774 \uc788\uc744\uae4c? \ub098\uc774\uac00 \ub9ce\uc73c\uba74 \uc0c8\ub85c\uc6b4 \ubcc0\ud654\uc640 \ud658\uacbd\uc5d0 \uc801\uc751\ud558\uae30 \ud798\ub4e0\uac78\uae4c? \ubc18\ub300\ub85c \ub098\uc774\uac00 \uc801\uc73c\uba74 \uc27d\uac8c \uc801\uc751 \ud560 \uc218 \uc788\ub2e4\ub294 \uac83\uc77c\uae4c?"}),"\n",(0,r.jsx)(t.h2,{id:"\ub098\uc774\ub77c\ub294-\ucee8\ud14d\uc2a4\ud2b8\uc758-\uc758\ubbf8",children:'"\ub098\uc774"\ub77c\ub294 \ucee8\ud14d\uc2a4\ud2b8\uc758 \uc758\ubbf8'}),"\n",(0,r.jsx)(t.p,{children:'\uc704\uc758 \ubb38\uc81c\uc5d0 \ub300\ud574 \uace0\ubbfc\ud558\uae30 \uc804\uc5d0, \ubb38\uc81c\uac00 \ub418\ub294 "\ub098\uc774"\uc5d0 \ub300\ud574, "\ub098\uc774"\ub77c\ub294 \ub2e8\uc5b4\uc758 \uc758\ubbf8\ub97c  \uc5b4\ub5bb\uac8c \ubc1b\uc544 \ub4e4\uc5ec\uc57c \ud560\uc9c0 \uc0dd\uac01\uc744 \ud574\ubd10\uc57c \ud560 \uac83 \uac19\ub2e4. \uc77c\ub2e8 \ud68c\uc0ac\uc5d0\uc11c \uc5c5\ubb34\ub97c \uc218\ud589\ud574\uc57c \ud558\ub294 \uac83\uc774\ub2c8\uae4c, \uc5c5\ubb34(\uae30\uc220)\uc640 \ub3d9\ub8cc \uadf8\ub9ac\uace0 \uc18c\ud1b5\uc758 \ucee8\ud14d\uc2a4\ud2b8\ub85c "\ub098\uc774"\uc758 \uc758\ubbf8\ub97c \uc0dd\uac01\ud574 \ubcfc \uc218 \uc788\uc744 \uac83 \uac19\ub2e4.'}),"\n",(0,r.jsx)(t.p,{children:'"\ub098\uc774", \ub2e8\uc21c\ud558\uac8c\ub294 \ud2b9\uc815\uc778\uc758 \uc5f0\ub839\uc744 \ub098\ud0c0\ub0b4\ub294 \ub2e8\uc5b4\ub85c \uc0ac\uc6a9\uc774 \ub418\uc9c0\ub9cc, \ud2b9\uc815 \ubd84\uc57c\uc758 \ucee8\ud14d\uc2a4\ud2b8\uc548\uc5d0\uc11c\ub294 "\uacbd\ub825"\uc73c\ub85c \ub300\uccb4\ud558\uc5ec \uc0ac\uc6a9\ud560 \uc218 \uc788\uc744 \uac83 \uc774\ub2e4. \uc989, "\ub098\uc774"\ub294 \ud2b9\uc815\uc778\uc774 \uc5b4\ub5a4 \ube44\uc9c0\ub2c8\uc2a4 \ud639\uc740 \uc5ed\ud65c \ubc0f \uae30\uc220\ubd84\uc57c\uc5d0 \ub300\ud55c \uacbd\ub825\uc73c\ub85c \uc0dd\uac01\ud574 \ubcfc \uc218 \uc788\uc744 \uac83\uc774\ub2e4.'}),"\n",(0,r.jsx)(t.p,{children:'\uadf8\ub9ac\uace0 \uc0ac\ud68c\uc801\uc778 \uce21\uba74\uc5d0\uc11c \ubcf4\uba74 \uc18c\ud1b5\uc758 \ubb38\uc81c\uac00 \uc788\uc744 \uc218 \uc788\uaca0\ub2e4. \uc5f0\ub839\uac04, \uc138\ub300\uac04 \uc18c\ud1b5\uc758 \ubb38\uc81c\ub294 \uc2ec\uc2ec\uce58 \uc54a\uac8c \ubc1c\uacac\ud560 \uc218 \uc788\ub2e4. \uadf8\uac74 \uc11c\ub85c\uc758 \uc18c\ud1b5 \ud639\uc740 \ub300\ud654\uc758 \ubc29\ubc95\uc774 \ub2e4\ub974\uae30\ub54c\ubb38\uc5d0, \uc0b6\uc758 \uacbd\ud5d8, \uc9c0\ub098\uc628 \ud658\uacbd\ub4e4\uc774 \ub2e4\ub974\uae30 \ub54c\ubb38\uc774\uc9c0 \uc54a\uc744\uae4c\ub77c\uace0 \uc0dd\uac01\ud574 \ubcf8\ub2e4. \uc18c\ud1b5\uc774\ub77c\ub294 \ucee8\ud14d\uc2a4\ud2b8\uc5d0\uc11c "\ub098\uc774"\ub294 \ud55c \uc0ac\ub78c\uc774 \uc9c0\ub098\uc628 \ud658\uacbd\ub4e4\uacfc \uc313\uc544\uc628 \uacbd\ud5d8\ub4e4\uc5d0 \uadfc\uac70\ud55c \ub300\ud654 \ubc29\uc2dd\uc73c\ub85c \ud574\uc11d\ud560 \uc218 \uc788\uc744 \uac83 \uac19\ub2e4.'}),"\n",(0,r.jsx)(t.h2,{id:"\ub098\uc774\uc640-\ub2a5\ub825-\uadf8\ub9ac\uace0-\uc18c\ud1b5",children:'"\ub098\uc774"\uc640 \ub2a5\ub825 \uadf8\ub9ac\uace0 \uc18c\ud1b5'}),"\n",(0,r.jsx)(t.p,{children:'\uc704\uc640 \uac19\uc740 \ud574\uc11d\uc744 \uac00\uc9c0\uace0 \uc0dd\uac01\ud574 \ubcf8\ub2e4\uba74, \ucc44\uc6a9\uc5d0 \uc788\uc5b4\uc11c "\ub098\uc774"\uac00 \uc815\ub9d0 \ubb38\uc81c\uac00 \ub418\ub294\uc9c0 \uc0dd\uac01\ud574 \ubcf4\uba74, "\ub098\uc774"\uac00 \ub9ce\ub2e4\ub294 \uac83\uc740 \uc5c5\ubb34 \uc801\uc778 \uacbd\ud5d8\uc774 \ub9ce\ub2e4\ub294 \uac83\uc774\ub41c\ub2e4. \uc989, \uc774\ubbf8 \uc874\uc7ac\ud558\ub294 \ube44\uc9c0\ub2c8\uc2a4 \ud639\uc740 \uc720\uc0ac\ud55c \ube44\uc9c0\ub2c8\uc2a4\uc5d0 \ub300\ud55c \uc11c\ube44\uc2a4\ub97c \ud558\uace0 \uc788\ub294 \ud68c\uc0ac\ub77c\uba74 \ub2f9\uc5f0 \uc5c5\ubb34 \uacbd\ud5d8\uc774 \ub9ce\uc740 \uc0ac\ub78c\uc774 \uc720\ub9ac\ud560 \uac83\uc774\ub2e4. \ub2e8, \uc0c8\ub85c\uc6b4 \ube44\uc9c0\ub2c8\uc2a4\uc758 \uacbd\uc6b0\uc5d0\ub294 \uadf8\ub7f0 \uacbd\ud5d8\uc774 \ud544\uc694\uac00 \uc5c6\uc744 \uc218 \uc788\uc744 \uac83\uc774\ub77c\uace0 \uc0dd\uac01\ud560 \uc218 \uc788\uaca0\uc9c0\ub9cc, \uc0c8\ub85c\uc6b4 \ube44\uc9c0\ub2c8\uc2a4\ub3c4 \uae30\uc874\uc758 \ube44\uc9c0\ub2c8\uc2a4\ub97c \uae30\ubc18\uc73c\ub85c \ub9cc\ub4e4\uc5b4\uc9c0\uac70\ub098, \uc544\ub2c8\uba74 \uae30\uc874\uc758 \ube44\uc9c0\ub2c8\uc2a4\uc758 \ud2c0\uc744 \uae68\ub294 \uc815\ub9d0 \uc0c8\ub85c\uc6b4 \ubaa8\ub378\uc774\ub77c\ud560 \uc9c0\ub77c\ub3c4 \ubd80\ubd84\uc801\uc73c\ub85c\ub294 \uae30\uc874\uc758 \ube44\uc9c0\ub2c8\uc2a4\ub97c \uc774\ud574\ud558\uace0 \uc788\uc5b4\uc57c \ud558\uc9c0 \uc54a\uc744\uae4c\ub77c\ub294 \uc0dd\uac01\uc774 \ub4e0\ub2e4.'}),"\n",(0,r.jsx)(t.p,{children:'\uadf8\ub9ac\uace0 \uae30\uc874\uc758 \ube44\uc9c0\ub2c8\uc2a4 \ud2c0\uc744 \uae68\ub294 \uc0c8\ub85c\uc6b4 \ubaa8\ub378\uc740 \ucc3d\uc758\uc801\uc774\uace0 \ud601\uc2e0\uc801\uc778 \ubd80\ubd84\uc774 \uac15\uc870\ub41c\ub2e4. \ubcf4\ud1b5 \uc80a\uc740 \ub098\uc774\uc5d0 \ucc3d\uc758\ub825\uacfc \ud601\uc2e0\uc774 \ucd5c\uace0\uc5d0 \ub2ec\ud55c\ub2e4\ub294 \ubbff\uc74c\uc774 \ub9ce\uc740 \uac83 \uac19\ub2e4. \ud558\uc9c0\ub9cc \uc815\ub9d0 \uadf8\ub7f4\uae4c? \ub09c \ucc3d\uc758\ub825\uacfc \ud601\uc2e0\uc801\uc778 \ub2a5\ub825\uc740 "\ub098\uc774"\uc640\ub294 \ubcc4\ub85c \uc0c1\uad00\uad00\uacc4\uac00 \uc5c6\ub2e4\uace0 \uc0dd\uac01\ud55c\ub2e4. \uc2e4 \uc608\ub85c, \uc5d0\ub514\uc2a8\uc758 \uacbd\uc6b0 \ubc1c\uba85\ud488\uc758 \ub300\ub2e4\uc218\uac00 \uc778\uc0dd\uc758 \ud6c4\ubc18\ubd80\uc5d0 \ub0b4\ub193\uc740 \uc544\uc774\ub514\uc5b4 \uc600\ub2e4.'}),"\n",(0,r.jsx)(t.p,{children:'\ud604\ub300\uc758 \uc0ac\ud68c\ub294 \ub9ce\uc740 \uc0c8\ub85c\uc6b4 \uae30\uc220\ub4e4\uc774 \uac1c\ubc1c\ub418\uace0 \uc0ac\uc6a9\uc774 \ub418\uace0 \uc788\ub2e4. \uadf8\ub7f0 \uc0c8\ub85c\uc6b4 \uae30\uc220\uc744 \ube60\ub974\uac8c \ud559\uc2b5\ud558\uace0 \uc5c5\ubb34\uc5d0 \uc801\uc6a9\ud558\ub294 \ub2a5\ub825\uc774 \ubc18\ub4dc\uc2dc \ud544\uc694\ud55c \uac83\uc774 \uc0ac\uc2e4\uc774\ub2e4. \uc0c8\ub85c\uc6b4 \uae30\uc220\uc744 \ud559\uc2b5\ud558\uace0 \uc801\uc6a9\ud558\ub294\ub370 "\ub098\uc774"\uac00 \ub9ce\uc73c\uba74 \ubd88\ub9ac\ud574 \ubcf4\uc774\ub294 \uac83\uc774 \uc0ac\uc2e4\uc774\ub2e4. \ud558\uc9c0\ub9cc \uc870\uae08\ub9cc \uc0c8\ub85c\uc6b4 \uae30\uc220\ub4e4\uc758 \ub0b4\uba74\uc744 \uc0b4\ud3b4\ubcf4\uba74, \ube44\uc9c0\ub2c8\uc2a4 \ubd80\ubd84\uacfc \ube44\uc2b7\ud558\uac8c, \uc0c8\ub85c\uc6b4 \uae30\uc220\ub4e4\uc740 \uae30\uc874 \uae30\uc220\ub4e4\uc744 \uac1c\uc120\ud558\uac70\ub098, \uae30\uc874 \uae30\uc220\ub4e4\uc744 \uc0c8\ub85c\uc6b4 \ubc29\ubc95\uc73c\ub85c \uc870\ud569\ud558\uc5ec \ub9cc\ub4e4\uc5b4 \uc9c0\ub294 \uacbd\uc6b0\uac00 \ub9ce\ub2e4. \uc989, \uacfc\uac70\uc758 \uae30\uc220 \uacbd\ud5d8\uc774 \uc644\uc804\ud788 \uc4f8\ubaa8 \uc5c6\uc5b4 \uc9c0\ub294 \uacbd\uc6b0\ub294 \uac70\uc758 \uc5c6\ub2e4\ub77c\uace0 \ubd10\ub3c4 \ubb34\ubc29 \ud560 \uac83\uc774\ub2e4.'}),"\n",(0,r.jsx)(t.p,{children:'\uadf8\ub7fc "\ub098\uc774"\uac00 \ub9ce\uc744 \uc218\ub85d \ub300\ud654\ud558\uae30\uac00 \ud798\ub4e4\uae4c? "\ub098\uc774"\uac00 \ub9ce\uc73c\uba74 \uc2e0\uccb4\uc801\uc778 \uae30\ub2a5\uc774 \uc800\ud558\ub418\ub294 \uac83\uc740 \ub9de\ub2e4. \uc800\ud558\ub418\ub294 \uae30\ub2a5 \uc911\uc5d0 \uccad\uac01 \uacfc \ub9d0\ud558\uae30\ub3c4 \ub4e4\uc5b4\uac00\uaca0\uc9c0\ub9cc, \uadf8 \uc815\ub3c4\ub85c \uc800\ud558\ub41c \uc2e0\uccb4 \uae30\ub2a5\uc744 \uac00\uc9c4 \ub098\uc774\ub77c\uba74 \ud604\uc7a5\uc5d0\uc11c \ud65c\ubc1c\ud788 \uc77c\uc744 \ud558\uae30\ubcf4\ub2e8 \ub178\ud6c4\uc758 \uc0b6\uc744 \uc0ac\ub294 \uac83\uc774 \ub9de\uc744 \uac83 \uac19\ub2e4. "\ub098\uc774"\uac00 \ub9ce\uc744 \uc218\ub85d \ub300\ud654\ud558\uae30 \ud798\ub4e0 \uac83\uc774 \uc544\ub2c8\ub77c \uadf8 \uc0ac\ub78c\uc758 \ubc31 \uadf8\ub77c\uc6b4\ub4dc\uc640 \ub300\ud654 \ud328\ud134\uc774 \ub9de\uc9c0 \uc54a\ub294 \uacbd\uc6b0\uac00 \ub354 \ub300\ud654\ud558\uae30 \ud798\ub4e0 \uac83\uc774\ub77c\uace0 \uc0dd\uac01\ub41c\ub2e4. \ub2e4\uc2dc \ub9d0\ud558\uba74, "\uaf30\ub300"\uc640\ub294 \ub300\ud654\ud558\uae30 \ud798\ub4e4\ub2e4\ub294 \uac83\uc774\ub2e4. \uadf8\ub7f0\ub370 \ubcf4\ud1b5 "\ub098\uc774"\uac00 \ub9ce\uc73c\uba74 "\uaf30\ub300"\ub85c \ucde8\uae09\ub418\ub294 \uacbd\uc6b0\uac00 \ub9ce\uc9c0\ub9cc, \uc774\ub294 \uc88b\uc9c0 \uc54a\ub2e4\uace0 \uc0dd\uac01\ub41c\ub2e4. "\uaf30\ub300"\ub294 \uc0c8\ub85c\uc6b4 \ubcc0\ud654\ub97c \ubc1b\uc544 \ub4e4\uc774\uc9c0 \uc54a\uace0 \uc790\uc2e0\ub9cc\uc758 \uc0dd\uac01, \uac00\uce58\uad00\uc744 \uace0\uc218\ud558\uc5ec \ud0c0\uc778\uc5d0\uac8c\uae4c\uc9c0 \uac15\uc694\ud558\ub294 \ubd80\ub958\ub97c \uc77c\uceeb\ub294 \ub9d0\ub85c \uc54c\uace0 \uc788\ub2e4. \uc989, "\ub098\uc774"\uac00 \ub9ce\ub2e4\uace0 "\uaf30\ub300"\uac00 \uc544\ub2c8\ub77c \uc790\uc2e0\ub9cc\uc758 \uc138\uc0c1\uc744 \uc9c0\ud0a4\ub824\ub294 \uace0\uc9d1\uacfc \ub9c8\uc74c\uc744 \uc5f4\uc9c0 \uc54a\ub294 \ubd88\ud1b5\uc774 "\uaf30\ub300"\ub97c \ub9cc\ub4e0\ub2e4\uace0 \uc0dd\uac01\ud55c\ub2e4. \uadf8\ub9ac\uace0 \ud2b9\uc815 \uc601\uc5ed\uc5d0 \ub300\ud55c \ud3b8\ud5a5\ub41c \uc790\ub9cc\uc2ec\uc774 "\uaf30\ub300"\uc758 \uc6d0\uc778\uc774\uc9c0 \uc54a\uc744\uae4c?'}),"\n",(0,r.jsx)(t.p,{children:'\uadf8\ub9ac\uace0 \ub2e4\ub978 \uc0ac\ub78c\uc744 "\ub098\uc774"\ub9cc\uc73c\ub85c \ud310\ub2e8\ud574\uc11c \uc123\ubd88\ub9ac \'\uc800 \uc0ac\ub78c\uc740 \ub098\uc774\uac00 \ub9ce\uc544\uc11c \uaf30\ub300\uc77c \uac70\uc57c\'\ub77c\uace0 \uc0dd\uac01\ud55c\ub2e4\uba74, \uc790\uae30 \uc790\uc2e0\ubd80\ud130 "\uaf30\ub300"\uac00 \uc544\ub2cc\uc9c0, \uadf8\ub807\uac8c \ub420 \uac00\ub2a5\uc131\uc774 \uc788\uc9c0\ub294 \uc54a\uc740\uc9c0 \uc0dd\uac01\ud574 \ubd10\uc57c \ud558\uc9c0 \uc54a\uc744\uae4c? "\ub098\uc774"\uac00 \ub9ce\ub2e4\uace0 "\uaf30\ub300"\uc77c \ud655\ub960\uc774 \ub192\ub2e4\ub294 \uadfc\uac70\ub294 \ub3c4\ub300\uccb4 \uc5b4\ub514\uc11c \ub098\uc628\uac74\uc9c0 \uc54c \uc218\uac00 \uc5c6\ub2e4.'}),"\n",(0,r.jsx)(t.h2,{id:"\uadf8\ub7fc-\ubb34\uc5c7\uc744-\ubd10\uc57c-\ud558\ub098",children:"\uadf8\ub7fc \ubb34\uc5c7\uc744 \ubd10\uc57c \ud558\ub098?"}),"\n",(0,r.jsx)(t.p,{children:'\ud68c\uc0ac\ub9c8\ub2e4, \uc5c5\ubb34\ub9c8\ub2e4 \uc911\uc694\ud55c \uc0ac\ud56d\ub4e4\uc740 \ub2e4\ub97c \uc218 \uc788\uaca0\uc9c0\ub9cc, \uc704\uc5d0\uc11c \uc5b8\uae09\ud55c \uc5c5\ubb34 \ub2a5\ub824\uacfc \uc18c\ud1b5\uc740 \uac00\uc7a5 \uacf5\ud1b5\uc801\uc73c\ub85c \ud544\uc694\ud55c \uc0ac\ud56d\uc77c \uac83\uc774\ub2e4. \uadf8 \uc5c5\ubb34 \ub2a5\ub825\uacfc \uc18c\ud1b5\uc758 \ubc29\ubc95\uacfc \ub2a5\ub825\uc744 "\ub098\uc774"\ub77c\ub294 \ud504\ub808\uc784\uc548\uc5d0\uc11c, \uadf8\uac83\ub3c4 \uc62c\ubc14\ub974\uc9c0\ub3c4 \uc54a\uc740 \ud504\ub808\uc784\uc548\uc5d0\uc11c \ubcf4\uc9c0 \ub9d0\uc544\uc57c  \ud560 \uac83\uc774\ub2e4. \uc5c5\ubb34 \ub2a5\ub825\uacfc \uc18c\ud1b5\uc740 "\ub098\uc774"\uc5d0 \uc808\ub300\uc801\uc778 \uc0c1\uad00\uad00\uacc4\ub97c \uac00\uc9c0\ub294 \uac83\uc774 \uc544\ub2c8\ub77c, \uac1c\uac1c\uc778\uc5d0 \ub530\ub77c \ub2e4\ub978 \uacbd\ud5d8\uacfc \uadf8 \uc0ac\ub78c\uc758 \ub2a5\ub825\uacfc \uc9c0\ub098\uc628 \ud658\uacbd\uc5d0\uc11c \ub098\uc624\ub294 \uac83\uc774\uae30\ub54c\ubb38\uc774\ub2e4. \uac1c\uac1c\uc778\uc744 "\ub098\uc774"\uc5d0 \ub300\ud55c \uc120\uc785\uacac\uc744 \ubc84\ub9ac\uace0 \uc815\ub9d0 \uac1d\uad00\uc801\uc73c\ub85c \ud310\ub2e8\ud574 \ubd10\uc57c \ud558\uc9c0 \uc54a\uc744\uae4c?'}),"\n",(0,r.jsx)(t.p,{children:"\uc6b0\ub9ac\ub294 \uc80a\uc740 \uc778\uc7ac\ub9cc\uc744 \uc6d0\ud55c\ub2e4'\ub77c\ub294 \ud68c\uc0ac\ub4e4\uc740 '\uc6b0\ub9ac\ub294 \uad49\uc7a5\ud55c \uc5c5\ubb34 \uac15\ub3c4\ub97c \uc694\uad6c\ud558\ub2c8, \uc80a\uace0 \uac15\ud55c \uccb4\ub825\uc744 \uac00\uc9c4 \uc0ac\ub78c\uc744 \uc6d0\ud55c\ub2e4'\ub77c\ub294 \uc758\ub3c4\ub97c \uc228\uae30\uace0 \uc788\ub294 \uac83\uc774 \uc544\ub2cc\uac00\ub77c\ub294 \uc704\ud5d8\ud55c \uc0dd\uac01\uc744 \ud574\ubcf8\ub2e4. \ud6a8\uc728\uc801\uc73c\ub85c, \ub2e8 \uc0dd\uc0b0\uc131\uc758 \uc624\ub958\uc5d0 \ube60\uc9c0\uc9c0 \uc54a\uace0, \uc77c\uc744 \ud560 \uc218 \uc788\ub294 \uc778\uc7ac\uc640 \uadf8\ub7f0 \uc778\uc7ac\ub4e4\uc774 \uc790\uc720\ub86d\uac8c \uc18c\ud1b5\ud558\uc5ec \uc758\uacac\uc744 \ub098\ub20c \uc218 \uc788\ub294 \ud658\uacbd\uc744 \ub9cc\ub4e4\uc5b4 \uc8fc\ub294 \uac83\uc774 \"\ub098\uc774\"\uc5d0 \uc0c1\uad00\uc5c6\uc774 \uc88b\uc740 \uc778\uc7ac\ub97c \ucc44\uc6a9\ud560 \uc218 \uc788\ub294 \ud604\uba85\ud55c \ubc29\ubc95\uc774\ub77c\uace0 \ub09c \uc0dd\uac01\ud55c\ub2e4."}),"\n",(0,r.jsx)(t.p,{children:'\ub9c8\uc9c0\ub9c9\uc73c\ub85c, "\ub098\uc774"\uac00 \ub9ce\uc74c\uc744 \ub2eb\ud78c \ub9c8\uc778\ub4dc \uc14b, \uaf30\ub300, \ub2f5\ub2f5\ud568, \ub808\uac70\uc2dc \ub4f1\ub4f1\uc73c\ub85c \ud574\uc11d\ud558\uace0 \ud574\uc11d\ub418\uae38 \uc6d0\ud558\ub294 \uc0ac\ub78c\ub4e4\uc774 \uc788\ub2e4\uba74, \ub2f9\uc7a5\uc5d0\ub294 "\ub098\uc774"\ub9ce\uc740 \uc0ac\ub78c\ub4e4\ub9cc\uc758 \ubb38\uc81c\ub85c \ubcf4\uc774\uaca0\uc9c0\ub9cc,  \uadf8\uac74 \ub2f9\uc2e0\uc774 \uba38\uc9c0 \uc54a\uc544 \ub9c8\uc8fc\ud574\uc57c\ud560 \ubb38\uc81c\uc774\uae30\ub3c4 \ud55c \uac83\uc774\ub2e4.'})]})}function d(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,r.jsx)(t,{...e,children:(0,r.jsx)(u,{...e})}):u(e)}},28453:(e,t,n)=>{n.d(t,{R:()=>a,x:()=>l});var r=n(96540);const i={},o=r.createContext(i);function a(e){const t=r.useContext(o);return r.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function l(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:a(e.components),r.createElement(o.Provider,{value:t},e.children)}}}]);